data_contract.filter_model_shapes:

set:     { filterType: "set", values: string[] }


text:    { filterType: "text", type: "contains|notContains|equals|notEqual|startsWith|endsWith", filter: string }
text2:   { filterType: "text", operator: "AND|OR", conditions: [ textCond, textCond ] }


number:  { filterType: "number", type: "equals|notEqual|greaterThan|greaterThanOrEqual|lessThan|lessThanOrEqual|inRange", filter: number, filterTo?: number }
number2: { filterType: "number", operator: "AND|OR", conditions: [ numberCond, numberCond ] }


date:    { filterType: "date", type: "equals|notEqual|lessThan|greaterThan|inRange", dateFrom: string, dateTo?: string }
date2:   { filterType: "date", operator: "AND|OR", conditions: [ dateCond, dateCond ] }


multi:   { filterType: "multi", filterModels: [ set|null, (text|number|date)|null ] }
